PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?difference WHERE {
  VALUES ?series_2008 {
    wd:Q3511262
  }
  VALUES ?series_1977 {
    wd:Q1004352
  }
  ?series_2008 wdt:P1350 ?games_2008 .
  ?series_1977 wdt:P1350 ?games_1977 .
  BIND(?games_2008 - ?games_1977 AS ?difference)
}
